import React, { useEffect, useMemo, useState } from 'react';
import { CreditCard, CheckCircle, Play, Shield, Users, Star, Loader } from 'lucide-react';
import axios from 'axios';
import ChatWidget from './components/ChatWidget';

function App() {
  const [landingConfig, setLandingConfig] = useState({
    enabled: true,
    mode: 'normal',
    promo_title: '',
    brand_text: 'Jellyfin Premium',
    logo_url: null,
    features: [],
    original_price: 29.9,
    promo_price: 19.9
  });
  const [landingLoading, setLandingLoading] = useState(true);
  const [reviews, setReviews] = useState([]);
  const [reviewsLoading, setReviewsLoading] = useState(true);
  const [reviewIndex, setReviewIndex] = useState(0);
  const [reviewForm, setReviewForm] = useState({ name: '', message: '', stars: 5 });
  const [reviewSending, setReviewSending] = useState(false);

  const [formData, setFormData] = useState({
    nome: '',
    email: '',
    telefone: '',
    senha: '',
    confirmacaoSenha: '',
    paymentType: 'trial'  // 'trial' ou 'full'
  });
  const [loading, setLoading] = useState(false);
  const [giftLoading, setGiftLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [giftCode, setGiftCode] = useState('');
  const [giftBuyEmail, setGiftBuyEmail] = useState('');
  const [giftQuantity, setGiftQuantity] = useState(5);
  const [verificationStep, setVerificationStep] = useState(false);
  const [verificationCode, setVerificationCode] = useState('');
  const [pendingPaymentType, setPendingPaymentType] = useState(null);
  const [nowTs, setNowTs] = useState(Date.now());

  useEffect(() => {
    const loadLanding = async () => {
      setLandingLoading(true);
      try {
        const res = await axios.get('/api/public/landing-config');
        setLandingConfig(res.data);
      } catch (e) {
        setLandingConfig({
          enabled: true,
          mode: 'normal',
          promo_title: '',
          brand_text: 'Jellyfin Premium',
          original_price: 29.9,
          promo_price: 19.9
        });
      } finally {
        setLandingLoading(false);
      }
    };

    loadLanding();
  }, []);

  useEffect(() => {
    const loadReviews = async () => {
      setReviewsLoading(true);
      try {
        const res = await axios.get('/api/public/reviews');
        const list = Array.isArray(res.data?.reviews) ? res.data.reviews : [];
        setReviews(list);
        setReviewIndex(0);
      } catch (e) {
        setReviews([]);
        setReviewIndex(0);
      } finally {
        setReviewsLoading(false);
      }
    };
    loadReviews();
  }, []);

